/**
 * @summary Get full pokedex with ownership status
 */
export const getGetPokedexUrl = (params?: GetPokedexParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/pokedex?${stringifiedParams}`
    : `/api/pokedex`;
};

export const getPokedex = async (
  params?: GetPokedexParams,
  options?: RequestInit,
): Promise<PokedexResponse> => {
  return customFetch<PokedexResponse>(getGetPokedexUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetPokedexQueryKey = (params?: GetPokedexParams) => {
  return [`/api/pokedex`, ...(params ? [params] : [])] as const;
};

export const getGetPokedexQueryOptions = <
  TData = Awaited<ReturnType<typeof getPokedex>>,
  TError = ErrorType<unknown>,
>(
  params?: GetPokedexParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getPokedex>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetPokedexQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getPokedex>>> = ({
    signal,
  }) => getPokedex(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getPokedex>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetPokedexQueryResult = NonNullable<
  Awaited<ReturnType<typeof getPokedex>>
>;
export type GetPokedexQueryError = ErrorType<unknown>;

/**
 * @summary Get full pokedex with ownership status
 */

export function useGetPokedex<
  TData = Awaited<ReturnType<typeof getPokedex>>,
  TError = ErrorType<unknown>,
>(
  params?: GetPokedexParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getPokedex>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetPokedexQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

